import{c as a,Q as s,j as i,m as r}from"./chunks/framework.DVkeSyfh.js";const f=JSON.parse('{"title":"Analysis families","description":"","frontmatter":{},"headers":[],"relativePath":"reference/analysis-families.md","filePath":"reference/analysis-families.md","lastUpdated":null}'),t={name:"reference/analysis-families.md"};function o(n,e,l,d,c,h){return s(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="analysis-families" tabindex="-1">Analysis families <a class="header-anchor" href="#analysis-families" aria-label="Permalink to &quot;Analysis families&quot;">​</a></h1><p>Audience: users and developers<br> Goal: define the analysis families and stored outputs<br> Type: reference</p><h2 id="sonara" tabindex="-1">SONARA <a class="header-anchor" href="#sonara" aria-label="Permalink to &quot;SONARA&quot;">​</a></h2><p>SONARA stores feature metadata, model information, and derived working fields in SQLite. It is used by SONARA search and as part of SET feature completeness.</p><h2 id="maest" tabindex="-1">MAEST <a class="header-anchor" href="#maest" aria-label="Permalink to &quot;MAEST&quot;">​</a></h2><p>MAEST analysis stores genre-oriented analysis and embeddings. The app can write stored MAEST genre labels to standard genre tags only through the explicit tag-writing workflow.</p><p>SET may use MAEST embeddings, but should not use MAEST genre labels for track selection.</p><h2 id="mert" tabindex="-1">MERT <a class="header-anchor" href="#mert" aria-label="Permalink to &quot;MERT&quot;">​</a></h2><p>MERT stores audio embeddings used for seed search and SET similarity.</p><h2 id="clap" tabindex="-1">CLAP <a class="header-anchor" href="#clap" aria-label="Permalink to &quot;CLAP&quot;">​</a></h2><p>CLAP stores audio embeddings used for text search and SET similarity.</p><h2 id="promoted-classifiers" tabindex="-1">Promoted classifiers <a class="header-anchor" href="#promoted-classifiers" aria-label="Permalink to &quot;Promoted classifiers&quot;">​</a></h2><p>Promoted classifier scoring reads existing SONARA features plus MERT and MAEST embeddings, then writes database-only scores to <code>track_classifier_scores</code>. Scoring does not decode audio or modify audio files.</p><h2 id="device-selection" tabindex="-1">Device selection <a class="header-anchor" href="#device-selection" aria-label="Permalink to &quot;Device selection&quot;">​</a></h2><p>Analysis commands accept <code>--device</code>. <code>auto</code> chooses CUDA when PyTorch can see a GPU, otherwise CPU. Explicit <code>cuda</code> should fail clearly when CUDA is not available.</p>',15)])])}const p=a(t,[["render",o]]);export{f as __pageData,p as default};
